CREATE TABLE IF NOT EXISTS public_reputation_scores (id BIGSERIAL PRIMARY KEY, subject_type VARCHAR(30) NOT NULL, subject_id BIGINT NOT NULL, score NUMERIC(5,2) NOT NULL, nps NUMERIC(5,2), punctuality_score NUMERIC(5,2), quality_score NUMERIC(5,2), updated_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS public_rankings (id BIGSERIAL PRIMARY KEY, ranking_type VARCHAR(40) NOT NULL, city VARCHAR(80), reference_date DATE NOT NULL DEFAULT CURRENT_DATE);
CREATE TABLE IF NOT EXISTS public_ranking_positions (id BIGSERIAL PRIMARY KEY, ranking_id BIGINT NOT NULL REFERENCES public_rankings(id), subject_type VARCHAR(30) NOT NULL, subject_id BIGINT NOT NULL, position INT NOT NULL, score NUMERIC(5,2) NOT NULL);
CREATE TABLE IF NOT EXISTS public_profile_views (id BIGSERIAL PRIMARY KEY, subject_type VARCHAR(30) NOT NULL, subject_id BIGINT NOT NULL, viewer_id BIGINT NULL, viewed_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS public_reputation_events (id BIGSERIAL PRIMARY KEY, subject_type VARCHAR(30) NOT NULL, subject_id BIGINT NOT NULL, event_type VARCHAR(60) NOT NULL, impact_score NUMERIC(5,2) NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_public_rankings AS SELECT r.ranking_type,r.city,p.position,p.subject_type,p.subject_id,p.score FROM public_rankings r JOIN public_ranking_positions p ON p.ranking_id=r.id;
